const url = $env.SUPABASE_URL || '';
const key = $env.SUPABASE_SERVICE_KEY || '';
if (!url || !key) {
  throw new Error('SUPABASE_URL or SUPABASE_SERVICE_KEY not set in environment');
}
return [{ json: { supabase_url: url, supabase_key: key } }];

const garmin = $input.first().json;

const hrv   = (garmin.hrv?.hrvSummary)    ?? {};
const sleep = (garmin.sleep?.dailySleepDTO) ?? {};
const stress = garmin.stress ?? {};
const bb    = (garmin.body_battery ?? [{}])[0] ?? {};
const spo2  = garmin.spo2 ?? {};
const resp  = garmin.respiration ?? {};

const totalSec = sleep.sleepTimeSeconds ?? 0;
const deepSec  = sleep.deepSleepSeconds ?? 0;
const remSec   = sleep.remSleepSeconds  ?? 0;
const lightSec = sleep.lightSleepSeconds ?? 0;
const awakeSec = sleep.awakeSleepSeconds ?? 0;

const bbValues = bb.bodyBatteryValuesArray ?? [];
const validBB = bbValues.map(([, v]) => v).filter(v => v != null);
const bbWake = validBB.length ? Math.max(...validBB) : null;

const sleepScore = (sleep.sleepScores?.overall?.value) ?? null;

const pct = (part, total) =>
  total > 0 ? parseFloat((part / total * 100).toFixed(1)) : null;

return [{
  json: {
    date: garmin.fetch_date,
    hrv_weekly_avg:       hrv.weeklyAvg   ?? null,
    hrv_last_night:       hrv.lastNightAvg ?? null,
    hrv_status:           hrv.status       ?? null,
    hrv_feedback:         hrv.feedbackPhrase ?? null,
    sleep_duration_h:     totalSec ? parseFloat((totalSec / 3600).toFixed(2)) : null,
    sleep_score:          sleepScore,
    sleep_deep_pct:       pct(deepSec,  totalSec),
    sleep_rem_pct:        pct(remSec,   totalSec),
    sleep_light_pct:      pct(lightSec, totalSec),
    sleep_awake_pct:      pct(awakeSec, totalSec),
    body_battery_wake:    bbWake,
    body_battery_sleep_gain: bb.charged ?? null,
    resting_hr:           garmin.sleep?.restingHeartRate ?? null,
    stress_avg:           stress.avgStressLevel ?? null,
    stress_max:           stress.maxStressLevel ?? null,
    spo2_avg:             spo2.averageSpO2 ?? spo2.avgSleepSpO2 ?? null,
    spo2_min:             spo2.lowestSpO2  ?? null,
    respiration_avg:      resp.avgSleepRespirationValue ?? null,
    raw_json:             garmin
  }
}];

const garmin = $('Fetch Garmin Data').first().json;
const activities = garmin.activities ?? [];
const fetchDate  = garmin.fetch_date;

if (activities.length === 0) {
  return [{ json: { activities: [] } }];
}

const mapped = activities.map(a => {
  const zones = [1,2,3,4,5].map(z => a[`hrTimeInZone_${z}`] ?? 0);
  const totalZone = zones.reduce((s, v) => s + v, 0);
  const zpct = i => totalZone > 0
    ? parseFloat((zones[i] / totalZone * 100).toFixed(1))
    : null;

  const speed = a.averageSpeed ?? 0;
  const startDate = (a.startTimeLocal ?? fetchDate).slice(0, 10);

  return {
    garmin_id:               a.activityId,
    date:                    startDate,
    activity_name:           a.activityName  ?? null,
    activity_type:           a.activityType?.typeKey ?? null,
    sport_type:              String(a.activityType?.parentTypeId ?? ''),
    duration_sec:            a.duration ? Math.round(a.duration) : null,
    distance_m:              a.distance ?? null,
    elevation_gain_m:        a.elevationGain ?? null,
    avg_speed_kmh:           speed ? parseFloat((speed * 3.6).toFixed(2)) : null,
    avg_pace_sec_per_km:     speed > 0 ? Math.round(1000 / speed) : null,
    avg_hr:                  a.averageHR != null ? Math.round(a.averageHR) : null,
    max_hr:                  a.maxHR != null ? Math.round(a.maxHR) : null,
    hr_zone_1_pct:           zpct(0),
    hr_zone_2_pct:           zpct(1),
    hr_zone_3_pct:           zpct(2),
    hr_zone_4_pct:           zpct(3),
    hr_zone_5_pct:           zpct(4),
    training_stress_score:   a.trainingStressScore ?? null,
    aerobic_training_effect: a.aerobicTrainingEffect ?? null,
    anaerobic_training_effect: a.anaerobicTrainingEffect ?? null,
    training_load_abs:       a.activityTrainingLoad ?? null,
    avg_power_w:             a.avgPower ? Math.round(a.avgPower) : null,
    avg_cadence:             (a.averageRunningCadenceInStepsPerMinute ?? a.avgBikingCadenceInRevPerMinute) != null
                               ? Math.round(a.averageRunningCadenceInStepsPerMinute ?? a.avgBikingCadenceInRevPerMinute)
                               : null,
    calories:                a.calories != null ? Math.round(a.calories) : null,
    temp_min_c:              a.minTemperature ?? null,
    temp_max_c:              a.maxTemperature ?? null,
    location_name:           a.locationName ?? null,
    start_lat:               a.startLatitude ?? null,
    start_lng:               a.startLongitude ?? null,
    raw_json:                a
  };
});

return [{ json: { activities: mapped } }];

const data = $input.first().json;
const daily = data.daily;

const wmoDesc = (code) => {
  if (code === 0) return 'Clear sky';
  if (code <= 3) return 'Partly cloudy';
  if (code <= 48) return 'Fog';
  if (code <= 57) return 'Drizzle';
  if (code <= 67) return 'Rain';
  if (code <= 77) return 'Snow';
  if (code <= 82) return 'Rain showers';
  if (code <= 86) return 'Snow showers';
  return 'Thunderstorm';
};

const rows = daily.time.map((date, i) => ({
  date,
  fetched_at:             new Date().toISOString(),
  temp_max_c:             daily.temperature_2m_max[i],
  temp_min_c:             daily.temperature_2m_min[i],
  feels_like_max_c:       daily.apparent_temperature_max[i],
  feels_like_min_c:       daily.apparent_temperature_min[i],
  precipitation_mm:       daily.precipitation_sum[i],
  precipitation_prob_pct: daily.precipitation_probability_max[i],
  wind_speed_kmh:         daily.wind_speed_10m_max[i],
  wind_direction_deg:     daily.wind_direction_10m_dominant[i],
  uv_index_max:           daily.uv_index_max[i],
  weather_code:           daily.weathercode[i],
  weather_description:    wmoDesc(daily.weathercode[i])
}));

return [{ json: { rows } }];

const garmin = $('Fetch Garmin Data').first().json;
const gear = garmin.gear ?? {};

const rows = [];
for (const [activityId, gearList] of Object.entries(gear)) {
  if (!Array.isArray(gearList)) continue;
  for (const g of gearList) {
    const pk = g.gearPk ?? g.uuid ?? null;
    if (!pk) continue;
    rows.push({
      garmin_id:    parseInt(activityId),
      gear_pk:      String(pk),
      gear_type:    g.gearTypeName ?? g.gearType ?? null,
      display_name: g.displayName ?? g.customMakeModel ?? null
    });
  }
}

if (rows.length === 0) {
  return [{ json: { gear_rows: [] } }];
}
return [{ json: { gear_rows: rows } }];
